body:
mypy analysis fails when assigning an `FRect` to `Sprite.rect` and some other operations, like in example code below. This PR uses `Union[FRect, Rect]` in places where only `Rect` was allowed in sprite.pyi to fix that.

This fixes #2300.

Code below results in 6 mypy errors unpatched, no errors with PR.
```python
import pygame


class SpriteSubclass(pygame.sprite.Sprite):
    def __init__(self, groups=()) -> None:
        super().__init__(groups)
        self.rect = pygame.FRect(0, 0, 100, 100)


s = SpriteSubclass()
frect = pygame.FRect(0, 0, 1, 1)
s.rect = frect


class DirtySpriteSubclass(pygame.sprite.DirtySprite):
    def __init__(self, groups=()) -> None:
        super().__init__(groups)
        self.source_rect = pygame.FRect(0, 0, 100, 100)


ab: pygame.sprite.AbstractGroup = pygame.sprite.AbstractGroup()
ab.lostsprites = [frect]
ab.spritedict = {s: frect}


class ABSubclass(pygame.sprite.AbstractGroup):
    def draw(self, surface: pygame.Surface) -> list[pygame.FRect | pygame.Rect]:
        return [frect]

```
